using Contoso.Pricing;

namespace Contoso.Pricing.Tests;

[TestClass]
public sealed class PriceCalculatorTests
{
    private PriceCalculator _calculator = null!;

    [TestInitialize]
    public void Setup() => _calculator = new PriceCalculator();

    // ── CalculateTotal: DataRow (compile-time constants) ────────────────

    [TestMethod]
    [DataRow(10.00, 1, 0.0,  10.00,  DisplayName = "Single item, no tax")]
    [DataRow(10.00, 5, 0.0,  50.00,  DisplayName = "Multiple items, no tax")]
    [DataRow(10.00, 1, 0.10, 11.00,  DisplayName = "Single item, 10% tax")]
    [DataRow(25.50, 3, 0.08, 82.62,  DisplayName = "Fractional price, 8% tax")]
    [DataRow(0.00,  5, 0.10, 0.00,   DisplayName = "Zero unit price")]
    [DataRow(10.00, 0, 0.10, 0.00,   DisplayName = "Zero quantity")]
    [DataRow(99.99, 1, 1.0,  199.98, DisplayName = "100% tax rate (max boundary)")]
    [DataRow(99.99, 1, 0.0,  99.99,  DisplayName = "0% tax rate (min boundary)")]
    public void CalculateTotal_ReturnsExpectedResult(
        double unitPrice, int quantity, double taxRate, double expected)
    {
        var result = _calculator.CalculateTotal(
            (decimal)unitPrice, quantity, (decimal)taxRate);

        Assert.AreEqual((decimal)expected, result);
    }

    [TestMethod]
    [DataRow(-1.00, 1,  0.10, DisplayName = "Negative unit price throws")]
    [DataRow(10.00, -1, 0.10, DisplayName = "Negative quantity throws")]
    public void CalculateTotal_InvalidInput_ThrowsArgumentOutOfRange(
        double unitPrice, int quantity, double taxRate)
    {
        Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.CalculateTotal(
                (decimal)unitPrice, quantity, (decimal)taxRate));
    }

    [TestMethod]
    [DataRow(-0.01, DisplayName = "Tax rate below 0")]
    [DataRow(1.01,  DisplayName = "Tax rate above 1")]
    public void CalculateTotal_InvalidTaxRate_ThrowsArgumentOutOfRange(
        double taxRate)
    {
        Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.CalculateTotal(10m, 1, (decimal)taxRate));
    }

    // ── ApplyDiscount: DynamicData (complex / decimal-precise cases) ────

    public static IEnumerable<object[]> DiscountCases
    {
        get
        {
            yield return new object[] { 200.00m, 0m,   200.00m, "No discount" };
            yield return new object[] { 200.00m, 10m,  180.00m, "10% off" };
            yield return new object[] { 200.00m, 50m,  100.00m, "50% off" };
            yield return new object[] { 200.00m, 100m, 0.00m,   "100% off (free)" };
            yield return new object[] { 59.99m,  15m,  50.9915m, "Fractional result" };
            yield return new object[] { 0.00m,   25m,  0.00m,   "Zero price, any discount" };
            yield return new object[] { 1000.00m, 33.33m, 666.70m, "Repeating decimal percent" };
        }
    }

    [TestMethod]
    [DynamicData(nameof(DiscountCases))]
    public void ApplyDiscount_ReturnsExpectedResult(
        decimal price, decimal discountPercent, decimal expected, string scenario)
    {
        var result = _calculator.ApplyDiscount(price, discountPercent);

        Assert.AreEqual(expected, result, $"Failed for scenario: {scenario}");
    }

    public static IEnumerable<object[]> InvalidDiscountCases
    {
        get
        {
            yield return new object[] { 100m, -1m,   "Negative discount" };
            yield return new object[] { 100m, 100.01m, "Discount exceeds 100%" };
            yield return new object[] { 100m, 200m,  "Discount way over 100%" };
        }
    }

    [TestMethod]
    [DynamicData(nameof(InvalidDiscountCases))]
    public void ApplyDiscount_InvalidDiscount_ThrowsArgumentOutOfRange(
        decimal price, decimal discountPercent, string scenario)
    {
        Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.ApplyDiscount(price, discountPercent),
            $"Expected exception for scenario: {scenario}");
    }

    // ── FormatPrice: DynamicData from method ────────────────────────────

    public static IEnumerable<object[]> FormatPriceCases()
    {
        yield return new object[] { 9.99m,    "$",  "$9.99" };
        yield return new object[] { 1234.50m, "€",  "€1234.50" };
        yield return new object[] { 0.00m,    "$",  "$0.00" };
        yield return new object[] { 100m,     "£",  "£100.00" };
    }

    [TestMethod]
    [DynamicData(nameof(FormatPriceCases), DynamicDataSourceType.Method)]
    public void FormatPrice_ReturnsExpectedString(
        decimal price, string symbol, string expected)
    {
        var result = _calculator.FormatPrice(price, symbol);

        Assert.AreEqual(expected, result);
    }
}

